"use client";

import { useState, useRef, useEffect } from "react";
import { X, Minus, Plus, Gift, Truck, CheckCircle } from "lucide-react";
import { useOrderModal } from "@/context/OrderModalContext";

const PRICE = 40000;

export default function OrderModal() {
  const { isOpen, closeModal } = useOrderModal();
  const [firstName, setFirstName] = useState("");
  const [lastName, setLastName] = useState("");
  const [location, setLocation] = useState("");
  const [phone, setPhone] = useState("");
  const [quantity, setQuantity] = useState(1);
  const [submitted, setSubmitted] = useState(false);
  const [errors, setErrors] = useState<Record<string, string>>({});
  const overlayRef = useRef<HTMLDivElement>(null);
  const firstInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isOpen && firstInputRef.current) {
      setTimeout(() => firstInputRef.current?.focus(), 100);
    }
  }, [isOpen]);

  const total = PRICE * quantity;

  const formatPrice = (amount: number) =>
    new Intl.NumberFormat("fr-FR").format(amount) + " FCFA";

  const validate = () => {
    const next: Record<string, string> = {};
    if (!firstName.trim()) next.firstName = "Veuillez entrer votre prénom.";
    if (!lastName.trim()) next.lastName = "Veuillez entrer votre nom.";
    if (!location.trim()) next.location = "Veuillez indiquer votre lieu de résidence.";
    if (!phone.trim()) next.phone = "Veuillez entrer votre numéro de téléphone.";
    else if (!/^[0-9+\s\-()]{6,15}$/.test(phone.trim()))
      next.phone = "Numéro invalide (ex : +229 97 00 00 00).";
    return next;
  };

  const handleSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length > 0) {
      setErrors(errs);
      return;
    }
    setSubmitted(true);
  };

  const handleReset = () => {
    setFirstName("");
    setLastName("");
    setLocation("");
    setPhone("");
    setQuantity(1);
    setErrors({});
    setSubmitted(false);
    closeModal();
  };

  if (!isOpen) return null;

  return (
    <div
      ref={overlayRef}
      className="fixed inset-0 z-50 flex items-end sm:items-center justify-center p-0 sm:p-4 animate-fade-in"
      style={{ backgroundColor: "rgba(44, 42, 41, 0.7)", backdropFilter: "blur(4px)" }}
      onClick={(e) => {
        if (e.target === overlayRef.current) closeModal();
      }}
    >
      <div
        className="relative w-full sm:max-w-lg bg-white rounded-t-3xl sm:rounded-2xl shadow-2xl overflow-hidden animate-slide-up max-h-[95dvh] flex flex-col"
        role="dialog"
        aria-modal="true"
        aria-labelledby="modal-title"
      >
        {/* Header */}
        <div className="flex items-center justify-between px-6 pt-6 pb-4 border-b border-cocoon-sand shrink-0">
          <div>
            <h2
              id="modal-title"
              className="text-xl font-bold text-cocoon-brown"
            >
              {submitted ? "Commande reçue !" : "Passer ma commande"}
            </h2>
            {!submitted && (
              <p className="text-sm text-cocoon-text mt-0.5">
                Remplissez le formulaire, nous vous rappelons.
              </p>
            )}
          </div>
          <button
            onClick={closeModal}
            className="p-2 rounded-full hover:bg-cocoon-cream transition-colors text-cocoon-brown-light hover:text-cocoon-brown"
            aria-label="Fermer"
          >
            <X size={20} />
          </button>
        </div>

        {/* Content */}
        <div className="overflow-y-auto flex-1">
          {submitted ? (
            <div className="flex flex-col items-center justify-center text-center px-6 py-12 gap-5">
              <div className="w-16 h-16 rounded-full bg-cocoon-sand flex items-center justify-center">
                <CheckCircle size={32} className="text-cocoon-green" />
              </div>
              <div>
                <h3 className="text-xl font-bold text-cocoon-brown mb-2">
                  Merci, {firstName}&nbsp;!
                </h3>
                <p className="text-cocoon-text leading-relaxed">
                  Votre commande de{" "}
                  <strong>{quantity} matelas Cocoon</strong> a bien été
                  enregistrée. Notre équipe vous contactera très prochainement
                  pour confirmer la livraison.
                </p>
              </div>
              <div className="w-full bg-cocoon-cream rounded-xl p-4 text-left space-y-2">
                <div className="flex items-center gap-2 text-sm text-cocoon-brown font-medium">
                  <Gift size={16} className="text-cocoon-terracotta shrink-0" />
                  Pompe manuelle offerte avec votre commande
                </div>
                <div className="flex items-center gap-2 text-sm text-cocoon-brown font-medium">
                  <Truck size={16} className="text-cocoon-terracotta shrink-0" />
                  Livraison gratuite partout au Bénin
                </div>
              </div>
              <button
                onClick={handleReset}
                className="mt-2 px-7 py-3 rounded-full bg-cocoon-brown text-cocoon-cream font-semibold text-sm hover:bg-cocoon-dark transition-colors"
              >
                Fermer
              </button>
            </div>
          ) : (
            <form onSubmit={handleSubmit} noValidate className="px-6 py-5 space-y-5">
              {/* Nom / Prénom */}
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label
                    htmlFor="firstName"
                    className="block text-sm font-semibold text-cocoon-brown mb-1.5"
                  >
                    Prénom <span className="text-cocoon-terracotta">*</span>
                  </label>
                  <input
                    ref={firstInputRef}
                    id="firstName"
                    type="text"
                    value={firstName}
                    onChange={(e) => {
                      setFirstName(e.target.value);
                      if (errors.firstName)
                        setErrors((prev) => ({ ...prev, firstName: "" }));
                    }}
                    placeholder="Amina"
                    className={`w-full px-4 py-3 rounded-xl border text-cocoon-brown text-sm placeholder:text-cocoon-sand-dark bg-white transition-colors focus:outline-none focus:ring-2 focus:ring-cocoon-terracotta/40 ${errors.firstName ? "border-red-400" : "border-cocoon-sand hover:border-cocoon-sand-dark"}`}
                  />
                  {errors.firstName && (
                    <p className="text-xs text-red-500 mt-1">{errors.firstName}</p>
                  )}
                </div>
                <div>
                  <label
                    htmlFor="lastName"
                    className="block text-sm font-semibold text-cocoon-brown mb-1.5"
                  >
                    Nom <span className="text-cocoon-terracotta">*</span>
                  </label>
                  <input
                    id="lastName"
                    type="text"
                    value={lastName}
                    onChange={(e) => {
                      setLastName(e.target.value);
                      if (errors.lastName)
                        setErrors((prev) => ({ ...prev, lastName: "" }));
                    }}
                    placeholder="Koffi"
                    className={`w-full px-4 py-3 rounded-xl border text-cocoon-brown text-sm placeholder:text-cocoon-sand-dark bg-white transition-colors focus:outline-none focus:ring-2 focus:ring-cocoon-terracotta/40 ${errors.lastName ? "border-red-400" : "border-cocoon-sand hover:border-cocoon-sand-dark"}`}
                  />
                  {errors.lastName && (
                    <p className="text-xs text-red-500 mt-1">{errors.lastName}</p>
                  )}
                </div>
              </div>

              {/* Lieu de résidence */}
              <div>
                <label
                  htmlFor="location"
                  className="block text-sm font-semibold text-cocoon-brown mb-1.5"
                >
                  Lieu de résidence{" "}
                  <span className="text-cocoon-terracotta">*</span>
                </label>
                <input
                  id="location"
                  type="text"
                  value={location}
                  onChange={(e) => {
                    setLocation(e.target.value);
                    if (errors.location)
                      setErrors((prev) => ({ ...prev, location: "" }));
                  }}
                  placeholder="Ex : Cotonou, Porto-Novo, Parakou…"
                  className={`w-full px-4 py-3 rounded-xl border text-cocoon-brown text-sm placeholder:text-cocoon-sand-dark bg-white transition-colors focus:outline-none focus:ring-2 focus:ring-cocoon-terracotta/40 ${errors.location ? "border-red-400" : "border-cocoon-sand hover:border-cocoon-sand-dark"}`}
                />
                {errors.location && (
                  <p className="text-xs text-red-500 mt-1">{errors.location}</p>
                )}
              </div>

              {/* Téléphone */}
              <div>
                <label
                  htmlFor="phone"
                  className="block text-sm font-semibold text-cocoon-brown mb-1.5"
                >
                  Numéro de téléphone{" "}
                  <span className="text-cocoon-terracotta">*</span>
                </label>
                <input
                  id="phone"
                  type="tel"
                  value={phone}
                  onChange={(e) => {
                    setPhone(e.target.value);
                    if (errors.phone)
                      setErrors((prev) => ({ ...prev, phone: "" }));
                  }}
                  placeholder="Ex : +229 97 00 00 00"
                  className={`w-full px-4 py-3 rounded-xl border text-cocoon-brown text-sm placeholder:text-cocoon-sand-dark bg-white transition-colors focus:outline-none focus:ring-2 focus:ring-cocoon-terracotta/40 ${errors.phone ? "border-red-400" : "border-cocoon-sand hover:border-cocoon-sand-dark"}`}
                />
                {errors.phone && (
                  <p className="text-xs text-red-500 mt-1">{errors.phone}</p>
                )}
              </div>

              {/* Quantité */}
              <div>
                <label className="block text-sm font-semibold text-cocoon-brown mb-1.5">
                  Quantité
                </label>
                <div className="flex items-center gap-4">
                  <div className="flex items-center border border-cocoon-sand rounded-xl overflow-hidden">
                    <button
                      type="button"
                      onClick={() => setQuantity((q) => Math.max(1, q - 1))}
                      className="w-11 h-11 flex items-center justify-center text-cocoon-brown hover:bg-cocoon-cream transition-colors disabled:opacity-40"
                      disabled={quantity <= 1}
                      aria-label="Réduire la quantité"
                    >
                      <Minus size={16} />
                    </button>
                    <span className="w-12 text-center font-bold text-cocoon-brown text-lg">
                      {quantity}
                    </span>
                    <button
                      type="button"
                      onClick={() => setQuantity((q) => q + 1)}
                      className="w-11 h-11 flex items-center justify-center text-cocoon-brown hover:bg-cocoon-cream transition-colors"
                      aria-label="Augmenter la quantité"
                    >
                      <Plus size={16} />
                    </button>
                  </div>
                  <div className="text-sm text-cocoon-text">
                    40 000 FCFA × {quantity}
                  </div>
                </div>
              </div>

              {/* Récapitulatif prix */}
              <div className="bg-cocoon-cream rounded-xl p-4 space-y-2.5">
                <div className="flex justify-between text-sm text-cocoon-text">
                  <span>
                    Matelas Cocoon × {quantity}
                  </span>
                  <span className="font-semibold text-cocoon-brown">
                    {formatPrice(total)}
                  </span>
                </div>
                <div className="flex items-center justify-between text-sm">
                  <span className="flex items-center gap-1.5 text-cocoon-green font-medium">
                    <Gift size={14} />
                    Pompe manuelle
                  </span>
                  <span className="font-semibold text-cocoon-green">Offerte</span>
                </div>
                <div className="flex items-center justify-between text-sm">
                  <span className="flex items-center gap-1.5 text-cocoon-green font-medium">
                    <Truck size={14} />
                    Livraison au Bénin
                  </span>
                  <span className="font-semibold text-cocoon-green">Gratuite</span>
                </div>
                <div className="pt-2 mt-2 border-t border-cocoon-sand flex justify-between items-center">
                  <span className="font-bold text-cocoon-brown">Total</span>
                  <span className="text-xl font-bold text-cocoon-brown">
                    {formatPrice(total)}
                  </span>
                </div>
              </div>

              {/* Submit */}
              <button
                type="submit"
                className="w-full py-4 rounded-full bg-cocoon-brown text-cocoon-cream font-bold text-base hover:bg-cocoon-dark active:scale-95 transition-all shadow-md hover:shadow-lg"
              >
                Confirmer ma commande — {formatPrice(total)}
              </button>

              <p className="text-center text-xs text-cocoon-brown-light pb-2">
                Paiement à la livraison · Pompe manuelle offerte · Livraison
                gratuite partout au Bénin
              </p>
            </form>
          )}
        </div>
      </div>
    </div>
  );
}
